INSERT INTO stays (name, description, category, region, address, latitude, longitude, price, max_guests, images, amenities, host_name, host_image, rating, review_count, created_at) VALUES
('북촌 고요한 아침', '서울 북촌한옥마을 한복판에 자리한 전통 한옥 스테이. 대청마루에서 바라보는 기와지붕 풍경이 일상의 쉼표를 선사합니다. 온돌방의 따스함과 정갈한 다과가 준비되어 있습니다.', '한옥', '서울', '서울특별시 종로구 북촌로 31', 37.5826, 126.9850, 189000, 2, ARRAY['https://images.unsplash.com/photo-1580587771525-78b9dba3b914?w=800','https://images.unsplash.com/photo-1600585154340-be6161a56a0c?w=800','https://images.unsplash.com/photo-1600596542815-ffad4c1539a9?w=800','https://images.unsplash.com/photo-1600607687939-ce8a6c25118c?w=800','https://images.unsplash.com/photo-1600585154526-990dced4db0d?w=800'], ARRAY['와이파이','주차','조식','다과','온돌','정원'], '김서연', 'https://images.unsplash.com/photo-1438761681033-6461ffad8d80?w=200', 4.9, 47, '2025-06-15T00:00:00Z'),

('전주 소담재', '전주 한옥마을의 고즈넉한 한옥 스테이. 한지 창호로 스며드는 아침 햇살, 마당의 감나무, 그리고 호스트가 직접 준비하는 전주식 아침밥이 특별합니다.', '한옥', '전라', '전북 전주시 완산구 한옥마을길 45', 35.8159, 127.1530, 145000, 4, ARRAY['https://images.unsplash.com/photo-1600585154340-be6161a56a0c?w=800','https://images.unsplash.com/photo-1600596542815-ffad4c1539a9?w=800','https://images.unsplash.com/photo-1600607687939-ce8a6c25118c?w=800','https://images.unsplash.com/photo-1600585154526-990dced4db0d?w=800','https://images.unsplash.com/photo-1580587771525-78b9dba3b914?w=800'], ARRAY['와이파이','주차','조식','마당','온돌','한복체험'], '이정희', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=200', 4.8, 62, '2025-05-20T00:00:00Z'),

('경주 달빛고택', '경주 교촌마을 인근의 200년 된 고택을 현대적으로 리모델링한 공간. 대청마루에 앉아 월성을 바라보며 시간의 흐름을 잊을 수 있습니다.', '한옥', '경상', '경북 경주시 교촌길 12', 35.8371, 129.2119, 168000, 3, ARRAY['https://images.unsplash.com/photo-1600596542815-ffad4c1539a9?w=800','https://images.unsplash.com/photo-1600607687939-ce8a6c25118c?w=800','https://images.unsplash.com/photo-1580587771525-78b9dba3b914?w=800','https://images.unsplash.com/photo-1600585154340-be6161a56a0c?w=800','https://images.unsplash.com/photo-1600585154526-990dced4db0d?w=800'], ARRAY['와이파이','주차','다과','온돌','정원','자전거'], '박도현', 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?w=200', 4.7, 38, '2025-07-01T00:00:00Z'),

('담양 죽림헌', '담양 죽녹원 인근, 대나무 숲에 둘러싸인 한옥. 바람에 흔들리는 대나무 소리를 들으며 자연 속 힐링을 경험할 수 있는 공간입니다.', '한옥', '전라', '전남 담양군 담양읍 죽녹원로 88', 35.3214, 126.9812, 132000, 2, ARRAY['https://images.unsplash.com/photo-1600607687939-ce8a6c25118c?w=800','https://images.unsplash.com/photo-1600585154526-990dced4db0d?w=800','https://images.unsplash.com/photo-1580587771525-78b9dba3b914?w=800','https://images.unsplash.com/photo-1600585154340-be6161a56a0c?w=800','https://images.unsplash.com/photo-1600596542815-ffad4c1539a9?w=800'], ARRAY['와이파이','주차','다과','온돌','대나무숲산책'], '최윤아', 'https://images.unsplash.com/photo-1544005313-94ddf0286df2?w=200', 4.8, 29, '2025-08-10T00:00:00Z'),

('안동 하회별장', '안동 하회마을이 한눈에 내려다보이는 언덕 위 한옥. 넓은 마당과 대청마루, 아궁이 체험까지 가능한 전통 스테이입니다.', '한옥', '경상', '경북 안동시 풍천면 하회종가길 7', 36.5396, 128.5189, 155000, 5, ARRAY['https://images.unsplash.com/photo-1600585154526-990dced4db0d?w=800','https://images.unsplash.com/photo-1580587771525-78b9dba3b914?w=800','https://images.unsplash.com/photo-1600585154340-be6161a56a0c?w=800','https://images.unsplash.com/photo-1600596542815-ffad4c1539a9?w=800','https://images.unsplash.com/photo-1600607687939-ce8a6c25118c?w=800'], ARRAY['와이파이','주차','조식','마당','온돌','아궁이체험'], '류진호', 'https://images.unsplash.com/photo-1500648767791-00dcc994a43e?w=200', 4.6, 41, '2025-04-25T00:00:00Z'),

('서촌 이음재', '경복궁 서쪽 서촌 골목에 숨어 있는 아담한 한옥. 모던한 인테리어와 전통 건축의 조화가 돋보이며, 주변 갤러리와 카페를 산책하기 좋습니다.', '한옥', '서울', '서울특별시 종로구 자하문로 42', 37.5791, 126.9712, 210000, 2, ARRAY['https://images.unsplash.com/photo-1580587771525-78b9dba3b914?w=800','https://images.unsplash.com/photo-1600607687939-ce8a6c25118c?w=800','https://images.unsplash.com/photo-1600596542815-ffad4c1539a9?w=800','https://images.unsplash.com/photo-1600585154340-be6161a56a0c?w=800','https://images.unsplash.com/photo-1600585154526-990dced4db0d?w=800'], ARRAY['와이파이','다과','온돌','세탁기','에어컨'], '한지수', 'https://images.unsplash.com/photo-1534528741775-53994a69daeb?w=200', 4.9, 33, '2025-09-05T00:00:00Z'),

('제주 돌담헌', '제주 성읍민속마을 인근의 제주 전통 초가를 현대적으로 재해석한 공간. 돌담길 너머로 보이는 오름과 들판이 제주의 풍경을 고스란히 담고 있습니다.', '한옥', '제주', '제주특별자치도 서귀포시 표선면 성읍리 22', 33.3940, 126.8021, 175000, 3, ARRAY['https://images.unsplash.com/photo-1600585154340-be6161a56a0c?w=800','https://images.unsplash.com/photo-1580587771525-78b9dba3b914?w=800','https://images.unsplash.com/photo-1600607687939-ce8a6c25118c?w=800','https://images.unsplash.com/photo-1600596542815-ffad4c1539a9?w=800','https://images.unsplash.com/photo-1600585154526-990dced4db0d?w=800'], ARRAY['와이파이','주차','조식','온돌','마당','귤따기체험'], '고은비', 'https://images.unsplash.com/photo-1494790108377-be9c29b29330?w=200', 4.7, 25, '2025-10-01T00:00:00Z'),

('월정리 파도소리', '제주 월정리 해변 바로 앞에 위치한 오션뷰 펜션. 탁 트인 에메랄드빛 바다를 바라보며 하루를 시작할 수 있는, 제주 여행의 완벽한 베이스캠프입니다.', '펜션', '제주', '제주특별자치도 제주시 구좌읍 월정리 1520', 33.5559, 126.7984, 198000, 4, ARRAY['https://images.unsplash.com/photo-1499793983690-e29da59ef1c2?w=800','https://images.unsplash.com/photo-1520250497591-112f2f40a3f4?w=800','https://images.unsplash.com/photo-1571896349842-33c89424de2d?w=800','https://images.unsplash.com/photo-1582719478250-c89cae4dc85b?w=800','https://images.unsplash.com/photo-1584132967334-10e028bd69f7?w=800'], ARRAY['와이파이','주차','바베큐','오션뷰','테라스','세탁기'], '양현우', 'https://images.unsplash.com/photo-1506794778202-cad84cf45f1d?w=200', 4.8, 89, '2025-03-10T00:00:00Z'),

('속초 설악 뷰하우스', '속초 시내에서 설악산을 한눈에 담을 수 있는 모던 펜션. 넓은 통유리 너머로 펼쳐지는 설악산 풍경과 깔끔한 인테리어가 매력적인 공간입니다.', '펜션', '강원', '강원도 속초시 설악산로 456', 38.1670, 128.5918, 165000, 4, ARRAY['https://images.unsplash.com/photo-1520250497591-112f2f40a3f4?w=800','https://images.unsplash.com/photo-1499793983690-e29da59ef1c2?w=800','https://images.unsplash.com/photo-1582719478250-c89cae4dc85b?w=800','https://images.unsplash.com/photo-1571896349842-33c89424de2d?w=800','https://images.unsplash.com/photo-1584132967334-10e028bd69f7?w=800'], ARRAY['와이파이','주차','바베큐','마운틴뷰','테라스','에어컨'], '정태민', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=200', 4.6, 55, '2025-04-15T00:00:00Z'),

('양양 서피비치 하우스', '양양 서피비치 도보 3분 거리의 서퍼 감성 펜션. 서핑 후 돌아와 따뜻한 물에 몸을 담그고, 테라스에서 석양을 바라보며 하루를 마무리할 수 있습니다.', '펜션', '강원', '강원도 양양군 현남면 인구해변길 15', 37.9258, 128.7753, 142000, 3, ARRAY['https://images.unsplash.com/photo-1571896349842-33c89424de2d?w=800','https://images.unsplash.com/photo-1499793983690-e29da59ef1c2?w=800','https://images.unsplash.com/photo-1520250497591-112f2f40a3f4?w=800','https://images.unsplash.com/photo-1582719478250-c89cae4dc85b?w=800','https://images.unsplash.com/photo-1584132967334-10e028bd69f7?w=800'], ARRAY['와이파이','주차','서핑보드대여','오션뷰','바베큐','야외샤워'], '김서진', 'https://images.unsplash.com/photo-1534528741775-53994a69daeb?w=200', 4.7, 73, '2025-05-01T00:00:00Z'),

('제주 소길댁', '제주 한림읍 소길리의 감귤밭 사이에 자리한 독채 펜션. 돌담과 감귤나무가 어우러진 제주 시골 풍경 속에서 진정한 제주를 만날 수 있습니다.', '펜션', '제주', '제주특별자치도 제주시 한림읍 소길리 33', 33.3601, 126.3451, 128000, 2, ARRAY['https://images.unsplash.com/photo-1584132967334-10e028bd69f7?w=800','https://images.unsplash.com/photo-1499793983690-e29da59ef1c2?w=800','https://images.unsplash.com/photo-1571896349842-33c89424de2d?w=800','https://images.unsplash.com/photo-1520250497591-112f2f40a3f4?w=800','https://images.unsplash.com/photo-1582719478250-c89cae4dc85b?w=800'], ARRAY['와이파이','주차','독채','감귤밭','바베큐','자전거'], '오민지', 'https://images.unsplash.com/photo-1494790108377-be9c29b29330?w=200', 4.9, 91, '2025-02-20T00:00:00Z'),

('가평 숲속의 아침', '가평 잣나무 숲 한가운데 위치한 통나무 펜션. 새소리에 잠을 깨고, 안개 낀 숲을 산책한 뒤, 넓은 데크에서 커피 한 잔의 여유를 느낄 수 있습니다.', '펜션', '경기', '경기도 가평군 상면 축령산로 234', 37.7953, 127.5113, 178000, 6, ARRAY['https://images.unsplash.com/photo-1582719478250-c89cae4dc85b?w=800','https://images.unsplash.com/photo-1584132967334-10e028bd69f7?w=800','https://images.unsplash.com/photo-1499793983690-e29da59ef1c2?w=800','https://images.unsplash.com/photo-1520250497591-112f2f40a3f4?w=800','https://images.unsplash.com/photo-1571896349842-33c89424de2d?w=800'], ARRAY['와이파이','주차','바베큐','숲산책','벽난로','스파'], '윤재혁', 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?w=200', 4.5, 64, '2025-06-30T00:00:00Z'),

('여수 밤바다 하우스', '여수 돌산대교가 한눈에 보이는 오션뷰 펜션. 밤이면 여수 밤바다의 야경이 통유리 너머로 펼쳐지며, 프라이빗한 자쿠지에서 특별한 시간을 보낼 수 있습니다.', '펜션', '전라', '전남 여수시 돌산읍 무술목길 78', 34.7148, 127.7669, 225000, 2, ARRAY['https://images.unsplash.com/photo-1499793983690-e29da59ef1c2?w=800','https://images.unsplash.com/photo-1582719478250-c89cae4dc85b?w=800','https://images.unsplash.com/photo-1520250497591-112f2f40a3f4?w=800','https://images.unsplash.com/photo-1584132967334-10e028bd69f7?w=800','https://images.unsplash.com/photo-1571896349842-33c89424de2d?w=800'], ARRAY['와이파이','주차','오션뷰','자쿠지','테라스','와인바'], '이수민', 'https://images.unsplash.com/photo-1438761681033-6461ffad8d80?w=200', 4.8, 52, '2025-07-15T00:00:00Z'),

('평창 하늘목장 로그하우스', '평창 해발 800m에 위치한 로그하우스. 여름엔 초록 목장, 겨울엔 설경이 펼쳐지며, 맑은 날엔 별이 쏟아지는 하늘을 볼 수 있습니다.', '펜션', '강원', '강원도 평창군 대관령면 목장길 67', 37.6838, 128.7365, 195000, 5, ARRAY['https://images.unsplash.com/photo-1520250497591-112f2f40a3f4?w=800','https://images.unsplash.com/photo-1571896349842-33c89424de2d?w=800','https://images.unsplash.com/photo-1584132967334-10e028bd69f7?w=800','https://images.unsplash.com/photo-1499793983690-e29da59ef1c2?w=800','https://images.unsplash.com/photo-1582719478250-c89cae4dc85b?w=800'], ARRAY['와이파이','주차','벽난로','바베큐','마운틴뷰','목장체험'], '신동윤', 'https://images.unsplash.com/photo-1500648767791-00dcc994a43e?w=200', 4.7, 48, '2025-08-20T00:00:00Z'),

('제주 애월 클리프 호텔', '제주 애월 해안 절벽 위에 자리한 부티크 호텔. 인피니티 풀에서 바라보는 수평선과 선셋은 잊을 수 없는 경험을 선사합니다.', '호텔', '제주', '제주특별자치도 제주시 애월읍 애월해안로 1234', 33.4661, 126.3260, 320000, 2, ARRAY['https://images.unsplash.com/photo-1566073771259-6a8506099945?w=800','https://images.unsplash.com/photo-1551882547-ff40c63fe5fa?w=800','https://images.unsplash.com/photo-1618773928121-c32242e63f39?w=800','https://images.unsplash.com/photo-1542314831-068cd1dbfeeb?w=800','https://images.unsplash.com/photo-1578683010236-d716f9a3f461?w=800'], ARRAY['와이파이','주차','수영장','조식','스파','오션뷰','바'], 'STAYLOG 제주', 'https://images.unsplash.com/photo-1560250097-0b93528c311a?w=200', 4.9, 124, '2025-01-15T00:00:00Z'),

('강릉 시포레 호텔', '강릉 경포 해변의 모던 부티크 호텔. 바다와 소나무 숲이 공존하는 특별한 로케이션에서, 미니멀한 디자인과 자연이 어우러진 휴식을 제공합니다.', '호텔', '강원', '강원도 강릉시 창해로 307', 37.8018, 128.9087, 245000, 2, ARRAY['https://images.unsplash.com/photo-1551882547-ff40c63fe5fa?w=800','https://images.unsplash.com/photo-1566073771259-6a8506099945?w=800','https://images.unsplash.com/photo-1542314831-068cd1dbfeeb?w=800','https://images.unsplash.com/photo-1618773928121-c32242e63f39?w=800','https://images.unsplash.com/photo-1578683010236-d716f9a3f461?w=800'], ARRAY['와이파이','주차','조식','오션뷰','카페','자전거'], 'STAYLOG 강릉', 'https://images.unsplash.com/photo-1560250097-0b93528c311a?w=200', 4.7, 87, '2025-02-10T00:00:00Z'),

('서울 성수 아트 호텔', '성수동 카페거리 한복판의 디자인 호텔. 로컬 아티스트와 협업한 인테리어와 루프탑 바에서의 서울 야경이 특별한 경험을 완성합니다.', '호텔', '서울', '서울특별시 성동구 성수이로 88', 37.5445, 127.0563, 280000, 2, ARRAY['https://images.unsplash.com/photo-1618773928121-c32242e63f39?w=800','https://images.unsplash.com/photo-1551882547-ff40c63fe5fa?w=800','https://images.unsplash.com/photo-1566073771259-6a8506099945?w=800','https://images.unsplash.com/photo-1578683010236-d716f9a3f461?w=800','https://images.unsplash.com/photo-1542314831-068cd1dbfeeb?w=800'], ARRAY['와이파이','조식','루프탑','바','피트니스','세탁서비스'], 'STAYLOG 서울', 'https://images.unsplash.com/photo-1560250097-0b93528c311a?w=200', 4.6, 96, '2025-03-20T00:00:00Z'),

('부산 해운대 웨이브 호텔', '해운대 해수욕장이 발아래 펼쳐지는 시사이드 호텔. 모든 객실에서 오션뷰를 감상할 수 있으며, 루프탑 인피니티 풀이 시그니처입니다.', '호텔', '경상', '부산광역시 해운대구 해운대해변로 456', 35.1586, 129.1604, 298000, 3, ARRAY['https://images.unsplash.com/photo-1542314831-068cd1dbfeeb?w=800','https://images.unsplash.com/photo-1566073771259-6a8506099945?w=800','https://images.unsplash.com/photo-1551882547-ff40c63fe5fa?w=800','https://images.unsplash.com/photo-1618773928121-c32242e63f39?w=800','https://images.unsplash.com/photo-1578683010236-d716f9a3f461?w=800'], ARRAY['와이파이','주차','수영장','조식','스파','오션뷰','피트니스'], 'STAYLOG 부산', 'https://images.unsplash.com/photo-1560250097-0b93528c311a?w=200', 4.8, 142, '2025-01-30T00:00:00Z'),

('제주 중문 그린 리조트', '제주 중문관광단지 내 자연 친화적 리조트. 넓은 정원과 야외 수영장, 그리고 한라산이 보이는 테라스에서 여유로운 제주 휴가를 보낼 수 있습니다.', '호텔', '제주', '제주특별자치도 서귀포시 중문관광로 72번길 35', 33.2503, 126.4120, 265000, 4, ARRAY['https://images.unsplash.com/photo-1578683010236-d716f9a3f461?w=800','https://images.unsplash.com/photo-1542314831-068cd1dbfeeb?w=800','https://images.unsplash.com/photo-1566073771259-6a8506099945?w=800','https://images.unsplash.com/photo-1551882547-ff40c63fe5fa?w=800','https://images.unsplash.com/photo-1618773928121-c32242e63f39?w=800'], ARRAY['와이파이','주차','수영장','조식','정원','키즈풀','마운틴뷰'], 'STAYLOG 제주', 'https://images.unsplash.com/photo-1560250097-0b93528c311a?w=200', 4.5, 78, '2025-04-05T00:00:00Z'),

('통영 루체 호텔', '통영 미륵산 케이블카 인근의 아트 호텔. 한려수도의 다도해 풍경과 통영의 예술적 감성을 담아낸 공간으로, 모든 객실에서 바다를 감상할 수 있습니다.', '호텔', '경상', '경남 통영시 발개로 178', 34.8382, 128.4229, 215000, 2, ARRAY['https://images.unsplash.com/photo-1566073771259-6a8506099945?w=800','https://images.unsplash.com/photo-1578683010236-d716f9a3f461?w=800','https://images.unsplash.com/photo-1551882547-ff40c63fe5fa?w=800','https://images.unsplash.com/photo-1542314831-068cd1dbfeeb?w=800','https://images.unsplash.com/photo-1618773928121-c32242e63f39?w=800'], ARRAY['와이파이','주차','조식','오션뷰','카페','루프탑'], 'STAYLOG 통영', 'https://images.unsplash.com/photo-1560250097-0b93528c311a?w=200', 4.6, 59, '2025-05-25T00:00:00Z'),

('제주 함덕 블루 호텔', '함덕 해수욕장이 코앞인 해변 호텔. 에메랄드빛 함덕 바다를 바라보며 조식을 즐기고, 해변까지 맨발로 걸어갈 수 있는 최적의 위치입니다.', '호텔', '제주', '제주특별자치도 제주시 조천읍 함덕해안로 55', 33.5432, 126.6694, 235000, 2, ARRAY['https://images.unsplash.com/photo-1551882547-ff40c63fe5fa?w=800','https://images.unsplash.com/photo-1618773928121-c32242e63f39?w=800','https://images.unsplash.com/photo-1566073771259-6a8506099945?w=800','https://images.unsplash.com/photo-1578683010236-d716f9a3f461?w=800','https://images.unsplash.com/photo-1542314831-068cd1dbfeeb?w=800'], ARRAY['와이파이','주차','조식','오션뷰','수영장','카페'], 'STAYLOG 제주', 'https://images.unsplash.com/photo-1560250097-0b93528c311a?w=200', 4.7, 103, '2025-06-10T00:00:00Z'),

('제주 협재 서핑캠프', '협재 해변의 자유로운 서퍼 감성 게스트하우스. 서핑 레슨부터 장비 대여까지, 서핑을 시작하기에 완벽한 곳. 저녁엔 게스트들과 함께 모닥불 파티를 즐겨보세요.', '게스트하우스', '제주', '제주특별자치도 제주시 한림읍 협재리 2540', 33.3938, 126.2396, 85000, 2, ARRAY['https://images.unsplash.com/photo-1555854877-bab0e564b8d5?w=800','https://images.unsplash.com/photo-1596178065887-1198b6148b2b?w=800','https://images.unsplash.com/photo-1590073242678-70ee3fc28e8e?w=800','https://images.unsplash.com/photo-1564078516393-cf04bd966897?w=800','https://images.unsplash.com/photo-1522771739844-6a9f6d5f14af?w=800'], ARRAY['와이파이','서핑레슨','서핑보드대여','모닥불','공용주방','세탁기'], '강태양', 'https://images.unsplash.com/photo-1506794778202-cad84cf45f1d?w=200', 4.6, 67, '2025-03-25T00:00:00Z'),

('부산 광안리 루프탑 하우스', '광안대교 야경이 한눈에 보이는 루프탑 게스트하우스. 탁 트인 옥상에서 바라보는 부산 밤바다와 다양한 국적의 여행자들과의 만남이 기다립니다.', '게스트하우스', '경상', '부산광역시 수영구 광안해변로 280', 35.1531, 129.1186, 78000, 2, ARRAY['https://images.unsplash.com/photo-1596178065887-1198b6148b2b?w=800','https://images.unsplash.com/photo-1555854877-bab0e564b8d5?w=800','https://images.unsplash.com/photo-1564078516393-cf04bd966897?w=800','https://images.unsplash.com/photo-1590073242678-70ee3fc28e8e?w=800','https://images.unsplash.com/photo-1522771739844-6a9f6d5f14af?w=800'], ARRAY['와이파이','루프탑','공용주방','세탁기','오션뷰','바베큐'], '백소라', 'https://images.unsplash.com/photo-1544005313-94ddf0286df2?w=200', 4.5, 88, '2025-04-30T00:00:00Z'),

('강릉 커피거리 하우스', '강릉 안목 커피거리에 위치한 감성 게스트하우스. 1층은 호스트가 운영하는 스페셜티 커피숍, 2층은 아늑한 게스트룸으로 커피 향에 젖는 여행을 할 수 있습니다.', '게스트하우스', '강원', '강원도 강릉시 창해로14번길 20', 37.7735, 128.9461, 92000, 2, ARRAY['https://images.unsplash.com/photo-1590073242678-70ee3fc28e8e?w=800','https://images.unsplash.com/photo-1555854877-bab0e564b8d5?w=800','https://images.unsplash.com/photo-1596178065887-1198b6148b2b?w=800','https://images.unsplash.com/photo-1522771739844-6a9f6d5f14af?w=800','https://images.unsplash.com/photo-1564078516393-cf04bd966897?w=800'], ARRAY['와이파이','카페','공용주방','세탁기','자전거','보드게임'], '임지훈', 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?w=200', 4.7, 54, '2025-05-15T00:00:00Z'),

('전주 한옥마을 여행자의 집', '전주 한옥마을 입구의 가성비 좋은 게스트하우스. 친절한 호스트가 추천하는 전주 맛집 투어와 한복 체험으로 특별한 전주 여행을 만들어 보세요.', '게스트하우스', '전라', '전북 전주시 완산구 전주객사5길 14', 35.8122, 127.1460, 68000, 2, ARRAY['https://images.unsplash.com/photo-1564078516393-cf04bd966897?w=800','https://images.unsplash.com/photo-1590073242678-70ee3fc28e8e?w=800','https://images.unsplash.com/photo-1555854877-bab0e564b8d5?w=800','https://images.unsplash.com/photo-1596178065887-1198b6148b2b?w=800','https://images.unsplash.com/photo-1522771739844-6a9f6d5f14af?w=800'], ARRAY['와이파이','공용주방','세탁기','한복대여','맛집가이드','자전거'], '송하은', 'https://images.unsplash.com/photo-1438761681033-6461ffad8d80?w=200', 4.8, 112, '2025-02-28T00:00:00Z'),

('제주 이호테우 게스트하우스', '제주 이호테우 해변 도보 1분 거리의 감성 게스트하우스. 조랑말 등대가 보이는 테라스에서 맥주 한 잔, 제주 공항에서 가장 가까운 해변 숙소입니다.', '게스트하우스', '제주', '제주특별자치도 제주시 이호일동 1665', 33.4972, 126.4537, 72000, 2, ARRAY['https://images.unsplash.com/photo-1522771739844-6a9f6d5f14af?w=800','https://images.unsplash.com/photo-1564078516393-cf04bd966897?w=800','https://images.unsplash.com/photo-1555854877-bab0e564b8d5?w=800','https://images.unsplash.com/photo-1590073242678-70ee3fc28e8e?w=800','https://images.unsplash.com/photo-1596178065887-1198b6148b2b?w=800'], ARRAY['와이파이','공용주방','테라스','세탁기','오션뷰','보드게임'], '현다은', 'https://images.unsplash.com/photo-1494790108377-be9c29b29330?w=200', 4.4, 76, '2025-06-20T00:00:00Z'),

('경주 황리단길 이스트', '경주 황리단길 중심의 트렌디한 게스트하우스. 낮에는 황리단길 카페와 맛집 탐방, 밤에는 옥상에서 바라보는 첨성대 야경으로 경주를 200% 즐길 수 있습니다.', '게스트하우스', '경상', '경북 경주시 포석로 1080', 35.8344, 129.2145, 82000, 3, ARRAY['https://images.unsplash.com/photo-1555854877-bab0e564b8d5?w=800','https://images.unsplash.com/photo-1522771739844-6a9f6d5f14af?w=800','https://images.unsplash.com/photo-1596178065887-1198b6148b2b?w=800','https://images.unsplash.com/photo-1564078516393-cf04bd966897?w=800','https://images.unsplash.com/photo-1590073242678-70ee3fc28e8e?w=800'], ARRAY['와이파이','공용주방','루프탑','세탁기','자전거','보드게임'], '정하율', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=200', 4.5, 63, '2025-07-05T00:00:00Z'),

('파주 헤이리 아트 스테이', '파주 헤이리 예술마을의 갤러리형 게스트하우스. 호스트인 작가의 작품으로 꾸며진 공간에서 예술적 영감을 받으며 특별한 하룻밤을 보낼 수 있습니다.', '게스트하우스', '경기', '경기도 파주시 탄현면 헤이리마을길 93', 37.7595, 126.6842, 95000, 2, ARRAY['https://images.unsplash.com/photo-1596178065887-1198b6148b2b?w=800','https://images.unsplash.com/photo-1564078516393-cf04bd966897?w=800','https://images.unsplash.com/photo-1522771739844-6a9f6d5f14af?w=800','https://images.unsplash.com/photo-1555854877-bab0e564b8d5?w=800','https://images.unsplash.com/photo-1590073242678-70ee3fc28e8e?w=800'], ARRAY['와이파이','주차','갤러리','공용주방','정원','아트체험'], '나예진', 'https://images.unsplash.com/photo-1534528741775-53994a69daeb?w=200', 4.6, 42, '2025-08-01T00:00:00Z');
